go.code:
const MX = 500000

var (
	isPrime = make([]bool, MX+1)
	primes  []int
	S       []int
)

func init() {
	for i := range isPrime {
		isPrime[i] = true
	}
	isPrime[0] = false
	isPrime[1] = false

	for i := 2; i <= MX; i++ {
		if isPrime[i] {
			primes = append(primes, i)
			if i*i <= MX {
				for j := i * i; j <= MX; j += i {
					isPrime[j] = false
				}
			}
		}
	}

	S = append(S, 0)
	t := 0
	for _, x := range primes {
		t += x
		if t > MX {
			break
		}
		if isPrime[t] {
			S = append(S, t)
		}
	}
}

func largestPrime(n int) int {
	i := sort.SearchInts(S, n+1)
	return S[i-1]
}

java.code:
class Solution {
    private static final int MX = 500000;
    private static final boolean[] IS_PRIME = new boolean[MX + 1];
    private static final List<Integer> PRIMES = new ArrayList<>();
    private static final List<Integer> S = new ArrayList<>();

    static {
        Arrays.fill(IS_PRIME, true);
        IS_PRIME[0] = false;
        IS_PRIME[1] = false;

        for (int i = 2; i <= MX; i++) {
            if (IS_PRIME[i]) {
                PRIMES.add(i);
                if ((long) i * i <= MX) {
                    for (int j = i * i; j <= MX; j += i) {
                        IS_PRIME[j] = false;
                    }
                }
            }
        }

        S.add(0);
        int t = 0;
        for (int x : PRIMES) {
            t += x;
            if (t > MX) {
                break;
            }
            if (IS_PRIME[t]) {
                S.add(t);
            }
        }
    }

    public int largestPrime(int n) {
        int i = Collections.binarySearch(S, n + 1);
        if (i < 0) {
            i = ~i;
        }
        return S.get(i - 1);
    }
}

